SELECT t.ticker, t.time FROM `tav2_bq.ticker` AS t WHERE (t.time >= '2020-01-01' AND t.time <= '2026-04-03') AND ((t.Volume_3M_P50*t.Price/ NULLIF(t.Inflation_7, 0))>1400000000.0) AND (t.Risk_Rating <= 5) AND (t.PE < 18.5) AND (t.PE > 5.0) AND (t.PB < 1.8) AND (t.PB > 0.47) AND (t.ROE_Min5Y > 0.04) AND ((t.NP_P0 - t.NP_P4)/ABS(t.NP_P4) > 0.12) AND (t.NP_P0/ NULLIF(t.NP_P1, 0)> 1.25) AND (t.NP_P1 > 0) AND (t.PCF > 2.0) AND (t.PCF < 19.0) AND (t.CF_OA_5Y/ NULLIF(t.OShares, 0) > 5500.0) AND ((t.Cash_P0/ (t.LtDebt_P0+1) >0.035) OR (ABS(t.IntCov_P0) > 4.5)) ORDER BY t.ticker, t.time